import java.util.Arrays;
import java.util.HashMap;
import java.util.HashSet;

class Solution {
    public static boolean solve(String x) {
        HashSet<Character> seen = new HashSet<>();
        for (char c : x.toCharArray()) {
            if (!seen.add(c)) return false;
        }
        return true;
    }
}
